SELECT WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step02.*, Item.[Description 2], WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step01.No_, WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step01.Prel_qty, IIf(Nz([prel_qty])<>[whsh_qty],"ERR","") AS TEST
FROM (WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step02 LEFT JOIN WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step01 ON (WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step02.[Source No_] = WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step01.[Link To Source No_]) AND (WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step02.[Assortment Code] = WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step01.[Assortment Code]) AND (WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step02.[Constant Variable Code] = WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step01.[Constant Variable Code]) AND (WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step02.[Item No_] = WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step01.[Item No_]) AND (WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step02.No_ = WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step01.[Whse_ Document Ref_ No_])) LEFT JOIN Item ON WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step02.[Item No_] = Item.No_
WHERE (((WMS_TestOUTPRE_Diverso_SpedWhse_DETTAGLIO_step02.No_)=[NumeroSpedizioneWarehouse]));

